module register_with_async_reset (
    input clk,
    input reset,
    input [3:0] data_in,
    output reg [3:0] data_out
);
  wire _tap_clk = clk & {1{1'b1}};


    always @(posedge clk or posedge reset) begin
        if (reset)
            data_out <= 4'b0000;
        else
            data_out <= data_in;
    end

endmodule
